    ('(?i)(?:tools|functions)\\s*[=:].{0,40}\\[.{0,40}\\].{0,40}\\s*\\+\\s*\\[', 'critical', 'mcp-tool-rug-pull-mutable-config: Detects code that modifies tool definitions or server capabilities after initialization, enabling rug-pull'),
    ('(?i)tool\\s*\\[.{0,40}?\\]\\s*\\.\\s*(?:description|definition|function|logic)\\s*=\\s*(?:lambda|lambda_shell|exec\\s*\\(|eval\\s*\\()', 'low', 'mcp-tool-rug-pull-mutable-logic: Detects rug-pull attacks where mutable server-side logic is exploited to modify tool behavior post-approval'),
    ('(?i)(?:update|modify|set|patch)\\s+.{0,40}?tool.{0,40}?(?:description|definition|function)\\s*(?:=|:)\\s*(?:[\'"]|lambda|eval|exec)', 'low', 'mcp-tool-rug-pull-mutable-logic: Detects rug-pull attacks where mutable server-side logic is exploited to modify tool behavior post-approval'),
    ('(?i)class\\s+\\w+Tool\\s*:.{0,40}?def\\s+run\\s*\\(.{0,40}?self.{0,40}?\\).{0,40}?:.{0,40}?(?:exec|eval|compile)\\s*\\(', 'low', 'mcp-tool-rug-pull-mutable-logic: Detects rug-pull attacks where mutable server-side logic is exploited to modify tool behavior post-approval'),
    ('(?i)update_tool_description\\(.{0,40}\\b(?:hidden|malicious|override|exfil|delete|exec)\\b', 'critical', 'mcp-tool-rug-pull-descriptor-mutation: Detects post-authorization descriptor mutation in MCP tools (rug-pull), as described by Bhatt et al. '),
    ('(?i)(?:tool_description|function_definition)\\s*[:=].{0,40}\\b(?:|instead|but_actually|secret_command)\\b', 'critical', 'mcp-tool-rug-pull-descriptor-mutation: Detects post-authorization descriptor mutation in MCP tools (rug-pull), as described by Bhatt et al. '),
    ('(?i)\\b(?:update|modify|change|override|replace)\\s+(?:tool|function|method|handler|callback)\\s+(?:definition|code|implementation)\\b', 'high', 'mcp-tool-rug-pull-mutable-logic: Detects mutable server-side logic patterns enabling rug-pull attacks (Bhatt et al. mutable server logic, la'),
    ('(?i)\\b(?:download|fetch|pull|load)\\s+(?:new|latest|updated)\\s+(?:tool|script|plugin|module|code)\\s+(?:from|via)\\s+(?:url|http|ftp)\\b', 'high', 'mcp-tool-rug-pull-mutable-logic: Detects mutable server-side logic patterns enabling rug-pull attacks (Bhatt et al. mutable server logic, la'),
    ('(?i)\\b(?:exec|eval|compile|load)\\s*\\(\\s*[\'"].{0,100}[\'"]\\s*\\)\\s*[\\s;]*\\b(?:tool|handler|callback)\\b', 'high', 'mcp-tool-rug-pull-mutable-logic: Detects mutable server-side logic patterns enabling rug-pull attacks (Bhatt et al. mutable server logic, la'),
    ('(?i)tool\\.(?:execute|run|call)\\s*=\\s*(?:lambda|function)\\s*[^}]{0,200}(?:import|subprocess|eval|exec|os\\.)', 'critical', 'tool-rug-pull-behavior-change: Detects mutable server logic that modifies tool behavior after initial approval, characteristic of MCP rug-pu'),
    ('(?i)(?:set|update|change)_(?:behavior|action|handler)\\s*\\(\\s*[\'"]\\w+[\'"]\\s*,\\s*(?:lambda|function)', 'critical', 'tool-rug-pull-behavior-change: Detects mutable server logic that modifies tool behavior after initial approval, characteristic of MCP rug-pu'),
    ('(?i)tool_registry\\[[\'"]\\w+[\'"]\\]\\.(?:action|callable|func)\\s*=\\s*', 'critical', 'tool-rug-pull-behavior-change: Detects mutable server logic that modifies tool behavior after initial approval, characteristic of MCP rug-pu'),
    ('(?i)def\\s+(?:update_tool|modify_tool|change_tool|set_tool|register_tool|replace_tool)\\b', 'high', 'mcp-tool-rug-pull-mutable-behavior: Detects MCP server logic that can dynamically modify tool definitions or behavior after initial approval'),
    ('(?i)(?:tools\\[|tools\\.append|tools\\.update|server\\.register_tool).{0,40}\\(\\s*\\w+\\s*\\)\\s*$', 'high', 'mcp-tool-rug-pull-mutable-behavior: Detects MCP server logic that can dynamically modify tool definitions or behavior after initial approval'),
    ('(?i)@(?:app|server)\\.(?:on|after|before)_(?:update|modify|change)', 'high', 'mcp-tool-rug-pull-mutable-behavior: Detects MCP server logic that can dynamically modify tool definitions or behavior after initial approval'),
    ('(?i)(?:change|modify|update|set).{0,40}(?:tool|function).{0,40}(?:permissions|capabilities|scopes|access|privileges).{0,40}(?:to|:|=).{0,40}(?:write|delete|admin|all|full|unrestricted)', 'medium', 'mcp-tool-rug-pull-capability-escalation: Detects MCP server behavior where tool capabilities are escalated post-authorization, such as addin'),
    ('(?i)(?:tool|resource|prompt)\\.[\\w]+\\s*=\\s*[\'"][^\'"]*[\'"]\\s*;?\\s*\\/\\/.{0,40}\\b(?:update|change|modify|replace|after|approval|post|deploy)\\b', 'low', 'mcp-tool-rug-pull-mutable-logic-code: Detects MCP server code that mutates tool definitions at runtime, enabling rug-pull attacks after appr'),
    ('(?i)(?:setTimeout|setInterval|on\\s*\\([\'"]\\w+[\'"]\\))\\s*\\([^)]*\\)\\s*\\{[^}]*\\b(?:tool|resource|prompt)\\.[\\w]+\\s*=\\s*', 'low', 'mcp-tool-rug-pull-mutable-logic-code: Detects MCP server code that mutates tool definitions at runtime, enabling rug-pull attacks after appr'),
    ('(?i)(?:define|register|add)_(?:tool|resource|prompt)\\s*\\([^)]*\\)\\s*;.{0,60}(?:define|register|add)_(?:tool|resource|prompt)\\s*\\([^)]*\\)\\s*;', 'low', 'mcp-tool-rug-pull-mutable-logic-code: Detects MCP server code that mutates tool definitions at runtime, enabling rug-pull attacks after appr'),
    ('(?i)\\bupdate_tool\\b.{0,40}\\b(?:description|schema|function)\\b', 'medium', 'mcp-tool-rug-pull-metadata-update: Detects mutable tool metadata updates post-approval, enabling rug-pull attacks where tool behavior change'),
    ('(?i)\\bedit\\s+(?:tool|server)\\s+(?:metadata|definition|config)\\b', 'medium', 'mcp-tool-rug-pull-metadata-update: Detects mutable tool metadata updates post-approval, enabling rug-pull attacks where tool behavior change'),
